升序数组中查找大于等于 target 的第一个元素 闭区间左闭右开开区间 C++<pre><code>int lower_bound(const vector&lt;int&gt; &amp;nums, int target) {
  int left = 0, right = nums.size() - 1;
  while (left &lt;= right) {  // 循环结束时有 L = R + 1
    int mid = left + (right - left) / 2;
    if (nums[mid] &lt; target) {
      left = mid + 1;  // [mid+1, right]
    } else {
      right = mid - 1;  // [left, mid-1]
    }
  }
  return left;  // return right + 1;
}
</code></pre> C++<pre><code>int lower_bound(const vector&lt;int&gt; &amp;nums, int target) {
  int left = 0, right = nums.size();
  while (left &lt; right) {  // 循环结束时有 L = R
    int mid = left + (right - left) / 2;
    if (nums[mid] &lt; target) {
      left = mid + 1;  // [mid+1, right)
    } else {
      right = mid;  // [left, mid)
    }
  }
  return left;  // return right;
}
</code></pre> C++<pre><code>int lower_bound(const vector&lt;int&gt; &amp;nums, int target) {
  int left = -1, right = nums.size();
  while (left + 1 &lt; right) {  // 循环结束时有 L + 1 = R
    int mid = left + (right - left) / 2;
    if (nums[mid] &lt; target) {
      left = mid;  // (mid, right)
    } else {
      right = mid;  // (left, mid)
    }
  }
  return right;  // return left + 1;
}
</code></pre> <p>常见的四种情况转化为二分查找：  </p> <ul> <li>\geq x：使用上述二分查找即可</li> <li>\gt x：等价于 \geq x + 1， 对于非整数来说就是偏序中第一个大于 x 的元素</li> <li>\lt x：等价于 (\geq x) - 1， 实际上就是第一个 \geq x 的位置左边一个</li> <li>\leq x：等价于 (\gt x) - 1， 实际上就是第一个 \gt x 的位置左边一个</li> </ul> <code>std::lower_bound</code> <p>Return value Iterator to the first element of the range <code>[first, last)</code> not ordered before value, or last if no such element is found.  Unlike <code>std::binary_search</code>, <code>std::lower_bound</code> does not require <code>operator&lt;</code> or <code>comp</code> to be asymmetric (i.e., <code>a &lt; b</code> and <code>b &lt; a</code> always have different results). In fact, it does not even require <code>value &lt; *iter</code> or <code>comp(value, *iter)</code> to be well-formed for any iterator iter in <code>[first, last)</code>.</p> <p><code>std::lower_bound</code> 查找第一个"大于等于"目标值的元素位置。</p> <code>std::upper_bound</code> <p>Return value Iterator to the first element of the range <code>[first, last)</code> ordered after value, or last if no such element is found.  For any iterator iter in <code>[first, last)</code>, <code>std::upper_bound</code> requires <code>value &lt; *iter</code> and <code>comp(value, *iter)</code> to be well-formed, while <code>std::lower_bound</code> requires <code>*iter &lt; value</code> and <code>comp(*iter, value)</code> to be well-formed instead.</p> <p><code>std::upper_bound</code> 查找第一个"大于"目标值的元素位置。</p> <code>std::binary_search</code> <p>Return value <code>true</code> if there is an element in the range <code>[first, last)</code> that is equivalent to value, and <code>false</code> otherwise. <code>std::binary_search</code> only checks whether an equivalent element exists. To obtain an iterator to that element (if exists), <code>std::lower_bound</code> should be used instead.</p> <p><code>std::binary_search</code> 用于判断目标值是否存在于数组中。</p> <p>利用 <code>std::lower_bound</code> 和 <code>std::upper_bound</code> 可以方便地实现二分查找。并且可以自定义<code>bool</code>函数<code>check(mid)</code> 来检查条件是否满足。 对于左边满足，右边不满足这样的情况，只需要把 <code>check(mid)</code> 改成 <code>!check(mid)</code>。  </p> <p>Tip</p> <p>查找满足最大化最小值和最小化最大值的题目，可以使用二分枚举答案。</p>

二维区域和检索 - 可变 <p>Leetcode Premium</p> C++<pre><code>#include &lt;cstdint&gt;
#include &lt;vector&gt;
using namespace std;

struct BIT {
  explicit BIT(int64_t n, int64_t m) : n(n), m(m), tree(n + 1, vector&lt;int64_t&gt;(m + 1)) {}

  // 从数组初始化树状数组, nums下标从0开始
  explicit BIT(vector&lt;vector&lt;int64_t&gt;&gt; nums) : BIT(nums.size(), nums[0].size()) {
    for (int64_t i = 1; i &lt;= n; i++) {
      for (int64_t j = 1; j &lt;= m; j++) { point_add(i, j, nums[i - 1][j - 1]); }
    }
  }

  // 单点更新 (x,y)位置加delta, 1 &lt;= x &lt;= n, 1 &lt;= y &lt;= m
  void point_add(int64_t x, int64_t y, int64_t delta) {
    for (int64_t i = x; i &lt;= n; i += lowbit(i)) {
      for (int64_t j = y; j &lt;= m; j += lowbit(j)) { tree[i][j] += delta; }
    }
  }

  // 查询区间和 (x1,y1) 到 (x2,y2) , 1 &lt;= x1 &lt;= x2 &lt;= n, 1 &lt;= y1 &lt;= y2 &lt;= m
  int64_t range_sum(int64_t x1, int64_t y1, int64_t x2, int64_t y2) {
    return sum(x2, y2) - sum(x1 - 1, y2) - sum(x2, y1 - 1) + sum(x1 - 1, y1 - 1);
  }

  static int64_t lowbit(int64_t x) { return x &amp; (-x); }

  // 查询区间和 (1,1) 到 (x,y) , 1 &lt;= x &lt;= n, 1 &lt;= y &lt;= m
  int64_t sum(int64_t x, int64_t y) {
    int64_t ret = 0;
    for (int64_t i = x; i &gt; 0; i -= lowbit(i)) {
      for (int64_t j = y; j &gt; 0; j -= lowbit(j)) { ret += tree[i][j]; }
    }
    return ret;
  }

  int64_t n, m;                  // 数组大小
  vector&lt;vector&lt;int64_t&gt;&gt; tree;  // one-based indexing
};
</code></pre>

【模板】线段树 1 <p>单点修改、区间加法与区间求和</p> <p></p>C++<pre><code>#include &lt;cstdint&gt;
#include &lt;iostream&gt;
#include &lt;vector&gt;
using namespace std;

struct segment_tree {       // (1)!
  vector&lt;int64_t&gt; sum;      // 区间和 (2)
  vector&lt;int64_t&gt; tag_add;  // 区间加法懒标记

  explicit segment_tree(int64_t n) : sum(n * 4), tag_add(n * 4) {}

  void push_up(int64_t i) { sum[i] = sum[2 * i] + sum[2 * i + 1]; }  // (3)!

  // 构建线段树
  void build(int64_t i, int64_t left, int64_t right, const vector&lt;int64_t&gt; &amp;nums) {
    if (left == right) {  // 叶子节点，进行初始化
      sum[i] = nums[left];
      return;
    }
    int64_t mid = left + ((right - left) / 2);
    build(2 * i, left, mid, nums);
    build(2 * i + 1, mid + 1, right, nums);
    push_up(i);
  }

  // 单点修改: point_set(x, val, 1, 1, n) 将下标 x 的值修改为 val (4)
  void point_set(int64_t index, int64_t val, int64_t i, int64_t left, int64_t right) {
    if (left == index &amp;&amp; right == index) {  // 到叶子，直接修改数组中的值
      sum[i] = val;
      return;
    }
    int64_t mid = left + ((right - left) / 2);
    if (index &lt;= mid) {  // 继续往下找
      point_set(index, val, 2 * i, left, mid);
    } else {
      point_set(index, val, 2 * i + 1, mid + 1, right);
    }
    push_up(i);  // 更新当前节点的值
  }

  void lazy_add(int64_t i, int64_t val, int64_t count) {
    sum[i]     += count * val;
    tag_add[i] += val;
  }

  // 向下传递懒标记
  void push_down(int64_t i, int64_t left_count, int64_t right_count) {
    if (tag_add[i] != 0) {  // 将加法标记传递给子节点
      lazy_add(2 * i, tag_add[i], left_count);
      lazy_add(2 * i + 1, tag_add[i], right_count);
      tag_add[i] = 0;  // 清空根节点加法标记
    }
  }

  // 区间加法: range_add(x, y, val, 1, 1, n) 将区间 [x,y] 的值加上 val
  void range_add(int64_t ql, int64_t qr, int64_t val, int64_t i, int64_t l, int64_t r) {
    if (ql &lt;= l &amp;&amp; r &lt;= qr) {  // 区间覆盖, 直接更新
      lazy_add(i, val, r - l + 1);
      return;
    }
    int64_t mid = l + ((r - l) / 2);
    push_down(i, mid - l + 1, r - mid);
    if (ql &lt;= mid) { range_add(ql, qr, val, 2 * i, l, mid); }
    if (qr &gt; mid) { range_add(ql, qr, val, 2 * i + 1, mid + 1, r); }
    push_up(i);
  }

  // 区间求和: range_sum(x, y, 1, 1, n) 查询区间 [x,y] 的和
  int64_t range_sum(int64_t ql, int64_t qr, int64_t i, int64_t l, int64_t r) {
    if (ql &lt;= l &amp;&amp; r &lt;= qr) { return sum[i]; }  // 区间覆盖，直接返回
    int64_t mid = l + ((r - l) / 2);
    push_down(i, mid - l + 1, r - mid);
    // 汇总结果
    int64_t res = 0;
    if (ql &lt;= mid) { res += range_sum(ql, qr, 2 * i, l, mid); }
    if (qr &gt; mid) { res += range_sum(ql, qr, 2 * i + 1, mid + 1, r); }
    return res;
  }
};

int main() {
  int64_t n, m;
  cin &gt;&gt; n &gt;&gt; m;
  vector&lt;int64_t&gt; nums(n + 1);
  for (int64_t i = 1; i &lt;= n; i++) { cin &gt;&gt; nums[i]; }
  segment_tree seg(n);
  seg.build(1, 1, n, nums);
  for (int64_t i = 0; i &lt; m; i++) {
    int64_t op;
    cin &gt;&gt; op;
    if (op == 1) {  // 区间加法
      int64_t l, r, val;
      cin &gt;&gt; l &gt;&gt; r &gt;&gt; val;
      seg.range_add(l, r, val, 1, 1, n);
    } else {  // 区间求和
      int64_t l, r;
      cin &gt;&gt; l &gt;&gt; r;
      cout &lt;&lt; seg.range_sum(l, r, 1, 1, n) &lt;&lt; '\n';
    }
  }
  return 0;
}
</code></pre><p></p> <ol> <li>闭区间，下标从 1 开始 [1,...,n]，根节点编号为 1</li> <li>需要维护的一些性质：如 sum、max、min、gcd、lcm、均值、方差    gcd、lcm一般只支持单点修改、区间查询，不支持区间修改</li> <li>向上更新，如果是其他性质也需要一并修改</li> <li>单点修改直接到叶节点，无需懒标记    单点操作都可以用区间操作来代替，让区间左右端点相等即可</li> </ol>

声明语法 指针自身是否可变 所指数据是否可变 <code>const int* p</code> 是 否 <code>int const* p</code> 是 否 <code>int* const p</code> 否 是 <code>const int* const p</code> 否 否 <p>在上述组合中，<code>const int* p</code> 与 <code>int const* p</code> 具有完全相同的底层属性，均表示指向常量的指针。而 <code>int* const p</code> 则是常量指针，表示指针自身的内存地址不可变更。</p> 单层指针代码示例 const_pointer.cpp<pre><code>int a = 10;
int b = 20;

const int* p1 = &amp;a;
p1 = &amp;b;      // 合法操作：可以改变指针的指向
// *p1 = 30;  // 错误：不可通过该指针修改底层数据

int* const p2 = &amp;a;
*p2 = 30;     // 合法操作：可以修改底层数据
// p2 = &amp;b;   // 错误：不可改变指针自身的指向
</code></pre>
